def classify_candidate(src, tgt, tgt_type, evidence, valid_types, section):
    """Classify based on careful reading of evidence + target type."""

    # Shorten valid_types list to set for faster checking
    valid = set(valid_types)
    ev_lower = evidence.lower()

    # REJECT patterns (these are clearly just mentions, not edges)

    # Materials are never edge targets in prose
    if tgt_type == 'object.material':
        return reject("material-mention-not-relational")

    # Titles alone are not edges
    if tgt_type == 'title':
        return reject("title-mention-not-relational")

    # EMIT patterns (real edges)

    # SIBLING_OF: when target is explicitly someone's brother/sister
    if tgt_type == 'character.human':
        # Careful: "contrast to her...brother" = sibling
        # Check if "brother" or "sister" appears in the evidence near the target mention
        if ('brother' in ev_lower or 'sister' in ev_lower) and 'SIBLING_OF' in valid:
            return emit("SIBLING_OF", evidence, section, tier=1)

        # SERVES: "in the service of Lord X"
        if 'in the service of' in ev_lower and 'SERVES' in valid:
            return emit("SERVES", evidence, section, tier=1)

        # PROTECTS: "Meera protects Rickon when..." - specific act of protecting
        if 'protects' in ev_lower and 'Rickon' in evidence:
            # This is Meera protecting Rickon
            if 'PROTECTS' in valid:
                return emit("PROTECTS", evidence, section, tier=2)

        # DREAMS_OF: "Bran dreamed of..." or "in his dreams"
        if ('dreamed of' in ev_lower or 'dreams of' in ev_lower) and 'DREAMS_OF' in valid:
            # Make sure it's the source doing the dreaming about the target
            if any(x in ev_lower for x in ['dreamed', 'dreams']):
                return emit("DREAMS_OF", evidence, section, tier=2)

    # LOCATED_AT: explicit location presence
    if tgt_type in ['place.location', 'place.region']:
        # "arrived at Winterfell", "stay at Winterfell"
        if any(x in ev_lower for x in ['arrived', 'stay', 'stays', 'remain']):
            if 'LOCATED_AT' in valid:
                return emit("LOCATED_AT", evidence, section, tier=2)

    # FIGHTS_IN / PARTICIPATES_IN: event participation
    if tgt_type.startswith('event.'):
        # "participated in the grand melee"
        if 'participated' in ev_lower or 'grand melee' in ev_lower:
            if tgt_type == 'event.tournament' and 'FIGHTS_IN' in valid:
                return emit("FIGHTS_IN", evidence, section, tier=1)
            elif 'PARTICIPATES_IN' in valid:
                return emit("PARTICIPATES_IN", evidence, section, tier=2)

    # DEFAULT: No edge found
    return reject("no-fitting-type-vocab-locked")


def emit(edge_type, evidence, section, tier=1):
    """Return an emit_edge decision."""
    snippet = evidence[:140] if len(evidence) > 140 else evidence
    return {
        "decision": "emit_edge",
        "candidate_kind": "source_target",
        "evidence_kind": "wiki-entity",
        "edge_type": edge_type,
        "evidence_snippet": snippet,
        "evidence_section": section,
        "evidence_paragraph_index": 0,
        "confidence_tier": tier
    }


def reject(reason):
    """Return a reject_just_mention decision."""
    return {
        "decision": "reject_just_mention",
        "candidate_kind": "source_target",
        "reason": reason
    }


def process_file(input_path, output_path):
    """Process all candidates in input file."""
    os.makedirs(os.path.dirname(output_path), exist_ok=True)

    with open(input_path) as f_in, open(output_path, 'w') as f_out:
        for line in f_in:
